#include <stdio.h>
int main() {
    int T, N, ai;
    char P[10];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %s", &N, P);
        int nim_sum = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &ai);
            if (ai % 2 == 0) {
                nim_sum ^= (ai / 2) % 2;
            } else {
                nim_sum ^= (ai + 1) / 2;
            }
        }
        if (nim_sum != 0) {
            if (strcmp(P, "Dee") == 0) {
                printf("Dee\n");
            } else {
                printf("Dum\n");
            }
        } else {
            if (strcmp(P, "Dee") == 0) {
                printf("Dum\n");
            } else {
                printf("Dee\n");
            }
        }
    }
    return 0;
}

